import json
import re

import requests


class TestJsonPathConstrainedMixin:
    """Test mixin for json_path constrained generation.

    Requires ``self.base_url`` to point to a running SGLang server.
    """

    def _run_decode_json_path(self, json_path, prompt, n=1):
        response = requests.post(
            self.base_url + "/generate",
            json={
                "text": prompt,
                "sampling_params": {
                    "temperature": 0 if n == 1 else 0.5,
                    "max_new_tokens": 256,
                    "n": n,
                    "json_path": json_path,
                },
                "stream": False,
            },
        )

        ret = response.json()
        print(json.dumps(ret, indent=2))
        print("=" * 100)

        if not isinstance(ret, list):
            self.fail(f"Expected response to be a list, but got {type(ret)}")

        for item in ret:
            text = item.get("text", "").strip()
            if not text:
                self.fail("Generated text is empty.")
            self._assert_json_path_match(text, json_path)

    # ------------------------------------------------------------------
    # Assertion helpers
    # ------------------------------------------------------------------

    def _assert_json_path_match(self, text, json_path):
        """Assert that *text* is valid JSON and that *json_path* resolves."""
        try:
            data = json.loads(text)
        except json.JSONDecodeError as exc:
            self.fail(
                f"Output is not valid JSON: {text!r}  (error: {exc})"
            )
        self._check_path_exists(data, json_path)

    def _check_path_exists(self, data, json_path):
        """Walk the JSON path manually and assert all expected keys/indices exist.

        Supports: ``.key``, ``['key']``, ``[*]``, ``[0]``/``[n]`` index.
        """
        # Strip leading '$'
        path = json_path[1:] if json_path.startswith("$") else json_path

        # Tokenise the path into segments
        segments = re.findall(
            r"""\.([A-Za-z_$][\w$]*)|\[(?:(\d+)|(\*)|['"]([^'"]+)['"]) \]""",
            path,
        )

        def _walk(node, remaining):
            if not remaining:
                return  # reached the end — success
            dot_key, idx_str, wildcard, bracket_key = remaining[0]
            rest = remaining[1:]

            key = dot_key or bracket_key
            if key:
                if not isinstance(node, dict):
                    self.fail(
                        f"Expected a JSON object at path segment {key!r} "
                        f"but got {type(node).__name__!r}. Full output: {data}"
                    )
                if key not in node:
                    self.fail(
                        f"Key {key!r} not found in JSON output. "
                        f"Available keys: {list(node.keys())}. "
                        f"json_path: {json_path!r}"
                    )
                _walk(node[key], rest)

            elif wildcard:
                if not isinstance(node, list):
                    self.fail(
                        f"Expected a JSON array for '[*]' but got "
                        f"{type(node).__name__!r}. json_path: {json_path!r}"
                    )
                if len(node) == 0:
                    self.fail(
                        f"Expected a non-empty array for '[*]' but got an "
                        f"empty list. json_path: {json_path!r}"
                    )
                # Check every element satisfies the remainder
                for element in node:
                    _walk(element, rest)

            elif idx_str:
                idx = int(idx_str)
                if not isinstance(node, list):
                    self.fail(
                        f"Expected a JSON array for '[{idx}]' but got "
                        f"{type(node).__name__!r}. json_path: {json_path!r}"
                    )
                if len(node) <= idx:
                    self.fail(
                        f"Array too short: need index {idx} but length is "
                        f"{len(node)}. json_path: {json_path!r}"
                    )
                _walk(node[idx], rest)

        _walk(data, segments)

    # ------------------------------------------------------------------
    # Concrete test cases
    # ------------------------------------------------------------------

    def test_json_path_simple_key(self):
        """$.name — output must be a JSON object with a 'name' field."""
        self._run_decode_json_path(
            json_path="$.name",
            prompt='Output a JSON object that has a "name" field:',
        )

    def test_json_path_nested_keys(self):
        """$.address.city — output must have nested address.city."""
        self._run_decode_json_path(
            json_path="$.address.city",
            prompt=(
                'Output a JSON object with an "address" object that contains a "city" field:'
            ),
        )

    def test_json_path_array_wildcard(self):
        """$.items[*].id — output must have items array where each element has id."""
        self._run_decode_json_path(
            json_path="$.items[*].id",
            prompt=(
                'Output a JSON object with an "items" array '
                'where each element has an "id" field:'
            ),
        )

    def test_json_path_array_index(self):
        """$.results[0].title — output must have a results array with at least one element."""
        self._run_decode_json_path(
            json_path="$.results[0].title",
            prompt=(
                'Output a JSON object with a "results" array '
                'where the first element has a "title" field:'
            ),
        )

    def test_json_path_deep_nesting(self):
        """$.store.book[*].author — classic bookstore example."""
        self._run_decode_json_path(
            json_path="$.store.book[*].author",
            prompt=(
                "Output a JSON bookstore inventory where store.book is an array "
                "and each book has an author field:"
            ),
        )

    def test_json_path_batch(self):
        """Run $.name with n=3 to exercise batched constrained decoding."""
        self._run_decode_json_path(
            json_path="$.name",
            prompt='Output a JSON object with a "name" field:',
            n=3,
        )

